const allData = []

let counter = 0;
do {
  try {
    const items = $items("RSS Feed Read", 0, counter).map(item => item.json);
    allData.push.apply(allData, items);
  } catch (error) {
    return [{json: {allData}}];  
  }

  counter++;
} while(true);

